// Amortized COMPRESSION preconditioning (self-contained, durable in ~/.flux-embed).
// Greedily DELETE words and SHORTEN words (sense-safe synonym with fewer tokens) in a STATIC prefix,
// accepting a change only when the answer holds across the whole query suite. Token-count drops cut the
// prefill LINEARLY and recur free on every request. Sound: output preserved, cost non-increasing.
import fs from 'fs';
import { analyzeSurface, inflectTo } from './fluency-gate.mjs';
const HOME = process.env.HOME;
const T = 0.60;                       // sense threshold (offline pass can be strict)
const PORT = process.argv[2] || '8100';

// ---- sense candidate generation (inline; no /tmp) ----
const SYN = JSON.parse(fs.readFileSync(`${HOME}/.flux-embed/synonyms.json`,'utf8'));
const DB = JSON.parse(fs.readFileSync(`${HOME}/.flux-embed/ctxemb.json`,'utf8'));
const DIM=896, keys=Object.keys(DB), mean=new Float64Array(DIM);
for (const k of keys){const v=DB[k];for(let i=0;i<DIM;i++)mean[i]+=v[i];} for(let i=0;i<DIM;i++)mean[i]/=keys.length;
const cen=(w)=>{const v=DB[w];if(!v)return null;const o=new Float64Array(DIM);for(let i=0;i<DIM;i++)o[i]=v[i]-mean[i];return o;};
const cos=(a,b)=>{let d=0,na=0,nb=0;for(let i=0;i<DIM;i++){d+=a[i]*b[i];na+=a[i]*a[i];nb+=b[i]*b[i];}return d/((Math.sqrt(na)*Math.sqrt(nb))||1);};
const senseSyns=(surface)=>{const {ending,lemmas}=analyzeSurface(surface);let lemma=null,entry=null;for(const l of lemmas){if(SYN[l]){lemma=l;entry=SYN[l];break;}}if(!lemma)return[];const lc=cen(lemma);if(!lc)return[];const out=new Set();for(const b of Object.keys(entry)){for(const cb of entry[b]){if(cb===lemma)continue;const cc=cen(cb);if(!cc)continue;if(cos(lc,cc)<T)continue;const s=inflectTo(cb,ending,b);if(s)out.add(s);}}return[...out];};

// ---- tokenizer + probe ----
const vocab = JSON.parse(fs.readFileSync('./apps/edge-workers/vocab-cache/qwen3-8b-temp-vocab.json')).vocab;
const vset = new Set(Object.keys(vocab));
const tok = (t) => { const ids=[]; for (const w of t.toLowerCase().split(/\s+/)){let s='Ġ'+w;while(s.length){let took='';for(let l=Math.min(s.length,24);l>=1;l--){const c=s.slice(0,l);if(vset.has(c)){took=c;break;}}if(!took){s=s.slice(1);continue;}ids.push(vocab[took]);s=s.slice(took.length);}} return ids; };
const cache = new Map();
const probe = async (t) => { if(cache.has(t))return cache.get(t); const ids=tok(t); const body=new Uint8Array(ids.length*4); const dv=new DataView(body.buffer); ids.forEach((id,i)=>dv.setUint32(i*4,id>>>0,true)); const j=await(await fetch(`http://127.0.0.1:${PORT}/precond-probe`,{method:'POST',headers:{'X-Max-New':'6','X-FFN-Leakage-Mode':'mask-input-low-70'},body})).json(); const r={active:j.active_input+j.active_hidden,gen:JSON.stringify(j.gen_tokens)}; cache.set(t,r); return r; };

// ---- the static prefix + the query suite that pins its behaviour ----
const SYS = process.env.SYS || 'you are a helpful assistant always respond in a polite and professional manner provide accurate and concise answers to the questions avoid unnecessary repetition and keep responses focused';
const QUERIES = ['what is the capital of france','how many days are in a week','what color is a clear sky','what is two plus three','name one primary color'];
const STOP = new Set('a an the of to in on at and or for'.split(' '));
// GATE=exact → full generated token string identical (hard soundness); GATE=first → the answer HEAD
// (first 2 generated tokens) identical (semantic: same answer, tolerant of downstream tone/format drift).
const GATE = process.env.GATE || 'exact';
const head = (g) => JSON.stringify(JSON.parse(g).slice(0,2));
const evalSys = async (sys) => { let act=0; const gens=[]; for(const q of QUERIES){const r=await probe(sys+' '+q); act+=r.active; gens.push(r.gen);} return {act:act/QUERIES.length, gens}; };
const holds = (gens, base) => GATE==='first' ? gens.every((g,k)=>head(g)===head(base[k])) : gens.every((g,k)=>g===base[k]);

const base = await evalSys(SYS);
const baseTok = tok(SYS).length;
let cur = SYS.split(/\s+/), curAct = base.act, ops = [], i = 0;
while (i < cur.length) {
  const w = cur[i], wl = w.replace(/[^a-z]/gi,'').toLowerCase();
  // 1) DELETE (skip core function words we never drop)
  if (!STOP.has(wl)) {
    const del = cur.slice(0,i).concat(cur.slice(i+1));
    const rd = await evalSys(del.join(' '));
    if (holds(rd.gens, base.gens)) { ops.push(`del:${w}`); cur=del; curAct=rd.act; continue; }
  }
  // 2) SHORTEN to a sense-safe synonym with fewer tokens
  if (wl.length >= 4) {
    for (const s of senseSyns(wl)) {
      if (!vset.has('Ġ'+s.toLowerCase()) || tok(s).length >= tok(w).length) continue;
      const trial=[...cur]; trial[i]=s;
      const r = await evalSys(trial.join(' '));
      if (holds(r.gens, base.gens)) { ops.push(`${w}→${s}`); cur=trial; curAct=r.act; break; }
    }
  }
  i++;
}
const fin = await evalSys(cur.join(' '));
const finTok = tok(cur.join(' ')).length;
console.log('ORIGINAL ('+baseTok+' tok):\n  '+SYS);
console.log('\nCOMPRESSED ('+finTok+' tok):\n  '+cur.join(' '));
console.log(`\nops (${ops.length}): ${ops.join(', ')}`);
console.log(`TOKENS:  ${baseTok} → ${finTok}   (-${(100*(baseTok-finTok)/baseTok).toFixed(1)}%)`);
console.log(`PREFILL: ${base.act.toFixed(0)} → ${fin.act.toFixed(0)} active_blocks   (-${(100*(base.act-fin.act)/base.act).toFixed(1)}% per request, recurs free)`);
console.log(`answer preserved across all ${QUERIES.length} queries: by construction (gate)`);
